// Taiwan Stock Trading Hours Check (UTC+8)
// Trading hours: Monday-Friday 9:00-13:30

const now = new Date();
const day = now.getUTCDay(); // 0=Sunday, 6=Saturday
const hour = now.getUTCHours() + 8; // Convert to Taiwan time
const minute = now.getUTCMinutes();

// Day check: Monday(1) to Friday(5)
const isWeekday = day >= 1 && day <= 5;

// Time check: 9:00 - 13:30
const isTradingHours = (hour > 9 || (hour === 9 && minute >= 0)) && 
                        (hour < 13 || (hour === 13 && minute <= 30));

const canTrade = isWeekday && isTradingHours;

const dayNames = ['Sunday', 'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday'];

return {
  json: {
    canTrade: canTrade,
    isWeekday: isWeekday,
    isTradingHours: isTradingHours,
    currentTime: now.toISOString(),
    taiwanTime: `${hour.toString().padStart(2,'0')}:${minute.toString().padStart(2,'0')}`,
    dayName: dayNames[day],
    message: canTrade ? 'Market is OPEN - Trading allowed' : 'Market is CLOSED - Trading not allowed'
  }
};

// Parse stock data and calculate changes
const data = $input.first().json['Global Quote'] || {};
const previousClose = parseFloat(data['08. previous close'] || 0);
const currentPrice = parseFloat(data['05. price'] || 0);
const change = parseFloat(data['09. change'] || 0);
const changePercent = parseFloat(data['10. change percent']?.replace('%','') || 0);

// Alert thresholds
const THRESHOLD_UP = 3.0;   // Alert if up > 3%
const THRESHOLD_DOWN = -3.0; // Alert if down > -3%

let alertLevel = 'normal';
if (changePercent >= THRESHOLD_UP) alertLevel = 'OVERBUUGHT';
else if (changePercent <= THRESHOLD_DOWN) alertLevel = 'OVERSOLD';

return {
  json: {
    symbol: data['01. symbol'] || '2330.TW',
    previousClose: previousClose,
    currentPrice: currentPrice,
    change: change,
    changePercent: changePercent,
    alertLevel: alertLevel,
    shouldAlert: Math.abs(changePercent) >= 3,
    volume: data['06. volume'],
    high: data['03. high'],
    low: data['04. low'],
    timestamp: new Date().toISOString()
  }
};

// Log monitoring result
const stock = $input.first().json;
console.log(`[Stock Monitor] ${stock.symbol} - Price: ${stock.currentPrice}, Change: ${stock.changePercent}%`);

return { json: stock };

// Market closed - log and skip trading
const check = $input.first().json;
console.log(`[Market Closed] ${check.message} - ${check.taiwanTime} ${check.dayName}`);

return { json: check };
